from __future__ import annotations


def diff_versions(previous, current, as_graph=False):
    changes = []
    for field in sorted(set(previous) | set(current)):
        before = previous.get(field)
        after = current.get(field)
        if before != after:
            changes.append({'field': field, 'before': before, 'after': after})
    if not as_graph:
        return changes
    return {'nodes': ['previous', 'current'], 'edges': [{'from': 'previous', 'to': 'current', **change} for change in changes]}

