from __future__ import annotations


def diff_versions(previous, current):
    output = []
    fields = sorted(set(list(previous.keys()) + list(current.keys())))
    for field in fields:
        old = previous.get(field)
        new = current.get(field)
        if old != new:
            output.append({'field': field, 'before': old, 'after': new})
    return output

